import { useEffect, useState } from 'react';
import { fetchDestinations } from '../services/api';
import DestinationCard from '../components/DestinationCards';
import CreateDestination from '../components/DestinationsCreate';
import '../styles/Groups.css';

export default function Destinations() {
    const [groups, setDestinations] = useState([]);
    const [showModal, setShowModal] = useState(false);

    useEffect(() => {
        fetchDestinations().then(setDestinations);
    }, []);

    // Extraire tous les membres uniques
    const allMembers = [...new Set(groups.flatMap(group => group.members || []))];

    return (
        <div className="groups-container">
            <div className="groups-header">
                <h1 className="groups-title">Nos destinations</h1>

                {allMembers.length > 0 && (
                    <p className="groups-members">
                        Membres :{' '}
                        {allMembers.map((member, index) => (
                            <span key={index}>
                                {member}
                                {index < allMembers.length - 1 ? ', ' : ''}
                            </span>
                        ))}
                    </p>
                )}

                <button
                    className="create-group-button"
                    onClick={() => setShowModal(true)}
                >
                    Créer une destination
                </button>
            </div>

            <div className="groups-grid">
                {groups.map(group => (
                    <DestinationCard
                        key={group.id}
                        id={group.id}
                        name={group.name}
                        image={group.image}
                        members={group.members}
                    />
                ))}
            </div>

            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content">
                        <button className="close-modal" onClick={() => setShowModal(false)}>✖</button>
                        <CreateDestination onClose={() => setShowModal(false)} />
                    </div>
                </div>
            )}
        </div>
    );
}
